class A:
    def __init__(self, **kw): super().__init__(**kw); print('A')

class B(A):
    def __init__(self, **kw): super().__init__(**kw); print('B')

class C(A):
    def __init__(self, **kw): super().__init__(**kw); print('C')

class D(B, C):
    def __init__(self, **kw): super().__init__(**kw); print('D')

print(D.__mro__)  # D -> B -> C -> A -> object
D()               # prints A, C, B, D  (each exactly once)

-- Setup
CREATE TEMP TABLE users (id INT, status TEXT);
INSERT INTO users VALUES (1,'active'),(2,'churned'),(3,NULL);

SELECT * FROM users WHERE status != 'churned';
-- Returns id=1 only; id=3 (NULL) silently excluded

SELECT * FROM users
WHERE id NOT IN (SELECT id FROM users WHERE status = 'x');
-- Returns all 3 rows (subquery empty)

-- Add a NULL to subquery
SELECT * FROM users
WHERE id NOT IN (SELECT id FROM users WHERE status IS NULL);
-- Returns 0 rows! NULL in subquery poisons entire NOT IN

-- Create JSONB column with GIN index
ALTER TABLE events ADD COLUMN meta JSONB;
CREATE INDEX ON events USING GIN (meta);

-- These queries use the GIN index:
SELECT * FROM events WHERE meta @> '{"env": "prod"}';
SELECT * FROM events WHERE meta ? 'user_id';

-- Path-based operator also index-supported:
CREATE INDEX ON events USING GIN (meta jsonb_path_ops);
SELECT * FROM events WHERE meta @@ '$.env == "prod"';

-- Serializable prevents phantom reads
BEGIN TRANSACTION ISOLATION LEVEL SERIALIZABLE;
SELECT COUNT(*) FROM active_jobs;  -- sees 4
INSERT INTO active_jobs ...;
-- If a concurrent txn already inserted, one will get:
-- ERROR: could not serialize access due to concurrent update
COMMIT;

-- Pessimistic alternative: advisory lock
SELECT pg_advisory_xact_lock(12345);
SELECT COUNT(*) FROM active_jobs;
INSERT INTO active_jobs ...;
COMMIT;
